            modelBuilder.Entity<Diagnosis>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.NationalId });

                entity.ToTable("Diagnosis");

                entity.Property(e => e.Id).UseIdentityColumn(1, 1).ValueGeneratedOnAdd();
                entity.Property(e => e.Diagnosis1)
                    .HasMaxLength(255)
                    .HasColumnName("Diagnosis");
                // الأعمدة الأساسية
                entity.Property(e => e.DiagnosisDate).HasColumnType("datetime");
                entity.Property(e => e.RiskLevel).HasMaxLength(50);
                entity.Property(e => e.Gender).HasMaxLength(10);
                entity.Property(e => e.IsDangerous).HasDefaultValue(false);
                entity.Property(e => e.LabConfirmed).HasDefaultValue(false);
                entity.Property(e => e.IsReported).HasDefaultValue(false);

                // 🔴 الأعمدة الجديدة (من الداتاسيت)
                entity.Property(e => e.Month);
                entity.Property(e => e.Year);
                entity.Property(e => e.WeekNumber);

                entity.HasOne(d => d.DoctorCodeNavigation).WithMany(p => p.Diagnoses)
                    .HasForeignKey(d => d.DoctorCode)
                    .HasConstraintName("FK_Diagnosis_Doctor");
            });
