            modelBuilder.Entity<Prescription>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.NationalId });

                entity.ToTable("Prescription");

                entity.Property(e => e.Id).UseIdentityColumn(1, 1).ValueGeneratedOnAdd();
                entity.Property(e => e.Medicines).HasMaxLength(255);
                entity.Property(e => e.Status).HasMaxLength(50);
                entity.Property(e => e.PrescriptionDate).HasColumnType("date");
