                    .HasForeignKey(d => d.DoctorCode)
                    .OnDelete(DeleteBehavior.ClientSetNull)
                    .HasConstraintName("FK_Prescription_Doctor");

                entity.HasOne(d => d.PharmacistCodeNavigation).WithMany(p => p.Prescriptions)
                    .HasForeignKey(d => d.PharmacistCode)
                    .HasConstraintName("FK_Prescription_Pharmacist");
            });
